; and may be inaccurate; treat them as hints, not verified annotation. Comments marked
; [DOC <manual> <page>] have been reconciled against the primary-source Microsoft SoftCard
; manuals (CP/M 2.20, (C) 1980) and are authoritative: S&HD = "Software and Hardware
; Details", CPMREF = the CP/M 2.2 Reference Manual. See the consolidated fact sheet at
; ../../docs/CPM_Manual_Reconcile_Facts.md.

; Generated by disasm6502 (clean-room decompile from this tree's own bytes).
; Source: CPM_BootLoader
; Range:  $0800-$13FF  (3072 bytes)
;
; [AI] This is the Microsoft SoftCard CP/M 6502 stage-2 boot loader. Stage 1 (the slot-6
;       Disk II controller $C600 P5/P6 PROM) reads track 0 sector 0 to $0800 and JMPs $0801.
;       From there this loader: (1) relocates itself one page at a time using a self-rewritten
;       indirect JMP, (2) drives its own private RWTS (read/write/track-seek engine, NOT DOS's)
;       to pull the ~0x1C-sector CP/M system image off the disk into the language card / main
;       RAM, then (3) probes the Apple II slots for the Z-80 SoftCard, installs the small
;       6502<->Z-80 RPC service code + Z-80 entry vectors into $0200-$03FF, and finally enters
;       the 6502 RPC service loop (at run address $03D2) which hands the machine to the Z-80.
;       A clean cold boot prints the three-line sign-on banner (APPLE II CP/M / 44K vers. 2.2X
;       / (C) 1980 MICROSOFT) and the "A>" prompt. The two error strings below name the
;       preconditions: "CAN'T FIND Z80 SOFTCARD" (no SoftCard present) and "MUST BOOT FROM
;       SLOT SIX" (booted from a non-slot-6 controller). [DOC S&HD 1-3/1-4,1-8]
;
; [AI] Decode notes for the principal data regions kept as .byte (NOT 6502 code at $08xx):
;       * $082D / $0F9D : DOS-3.3-style physical->logical sector skew/interleave tables.
;       * $083D         : ASCII "COPYRIGHT (C) 1980 MICROSOFT - NK" (high-bit set).
;       * $0C50/$0C56/$0C5C : arm-step on/off phase-time tables for the seek routine.
;       * $0D56         : the 6-and-2 nibble write-translate table (disk-byte values $96..$FF).
;       * $112F / $114E : the two high-ASCII error strings (see above).
;       * $1200-$13FF   : the INSTALL IMAGE. The loader copies it to $0200-$03FF (see
;                         RELOCATE_INSTALL_IMAGE) and only THEN does it run -- in TWO different
;                         worlds: the $03C0 RPC service loop and the $037C serial-out sub run on
;                         the 6502 (decoded as 6502 instructions below), while $034A-$037B are
;                         Z-80 instructions the SoftCard executes from that same RAM (INCBIN'd
;                         from CPM_BootLoader_ConInit.asm). The remaining $1380-$13BF cells are
;                         the Z-80 handler-address table and config data. Per-region annotations
;                         are at the install-image block at the end of this file.

.setcpu "6502"
.segment "CODE"

; ASCHI -- emit a string as high-bit-set ASCII (the Apple II screen-text convention
; this loader's banner/error messages use). Generic tooling; one byte per character
; with bit 7 forced on. Low-bit runs use plain  .byte "TEXT" ; a trailing high-bit
; CR ($8D) is emitted as a separate  .byte $8D  after the ASCHI.
.macro  ASCHI str
        .repeat .strlen(str), i
                .byte   .strat(str, i) | $80
        .endrep
.endmacro

; -- Zero page / page-3 working storage used by this loader --
;    $26/$27   sector engine scratch (running checksum, slot*16 index)
;    $2A-$2D   address-field fields read by READ_ADDRESS (volume/track/sector/csum)
;    $2E       phase-step scratch
;    $35       direction/flag bit for the arm stepper
;    $3C/$3D   pointer to the $Cn00 firmware page being probed for the SoftCard
;    $3E/$3F   (A2L/A2H) relocation/indirect-JMP pointer; later the RWTS data buffer pointer
;    $40/$41   firmware-page checksum compare temporaries
;    $46/$47   16-bit countdown used by the WAIT delay
;    $00       page counter alias used during self-relocation
;    $03E0-$03EB  the RWTS parameter block (built by LOAD_CPM, consumed by RWTS_ENGINE):
;                 $E0 cmd $E1 sector $E4 phase/dir $E5 last-phase $E6/$E7 drive-select pair
;                 $E8/$E9 buffer ptr lo/hi $EA result $EB mode

; -- External symbols --
H2                   = $002C             ; End column for horizontal line / right edge for HLINE
A2L                  = $003E             ; General-purpose pointer 2 low (reused as reloc + RWTS buffer ptr)
IN                   = $0200             ; GETLN input buffer ($0200-$02FF); install-image low half lands here
DOSRWA               = $03E3             ; (here) RWTS-style current-sector cell in the param block
SCRN_HOLE_0478_S0    = $0478             ; Screen-hole base; slot N adds N. Used here as current-track / scratch
SCRN_HOLE_04F8_S0    = $04F8             ; Screen-hole; slot N -> $04F8+N
SCRN_HOLE_0578_S0    = $0578             ; Screen-hole; slot N -> $0578+N
SCRN_HOLE_05F8_S0    = $05F8             ; Screen-hole; slot N -> $05F8+N (here: saved slot*16 X for the drive)
SCRN_HOLE_0678_S0    = $0678             ; Screen-hole; slot N -> $0678+N
SCRN_HOLE_06F8_S0    = $06F8             ; Screen-hole; slot N -> $06F8+N
LC_RAM_BANK2_RD      = $C080             ; Language card: read RAM bank 2 ($D000-$DFFF), write protect
LC_ROM_BANK2_WR      = $C081             ; Language card: read ROM, write enable bank 2 (read twice to enable write)
LC_RAM_BANK2_RDWR    = $C083             ; Language card: read/write RAM bank 2 (read twice to enable write)
LC_RAM_BANK1_RD      = $C088             ; Language card: read RAM bank 1, write protect
LC_ROM_BANK1_WR      = $C089             ; Language card: read ROM, write enable bank 1
LC_ROM_RD2           = $C08A             ; Language card: read ROM, write protect (alias)
LC_RAM_BANK1_RDWR    = $C08B             ; Language card: read/write RAM bank 1
TEXT                 = $FB2F             ; Set text mode + reset window to full screen
COUT                 = $FDED             ; Output character A via (CSW). Default routes to COUT1 (screen)
SETKBD               = $FE89             ; Reset KSW to default keyboard input ($FD1B); CSWL,KSWL := $1B,$FD
SETVID               = $FE93             ; Reset CSW to default screen output ($FDF0); CSWL,CSWH := $F0,$FD
PRERR                = $FF2D             ; Print 'ERR' + bell
RESTORE              = $FF3F             ; Restore 6502 regs A,X,Y,P from monitor save area $45-$48
SAVE                 = $FF4A             ; Save 6502 regs A,X,Y,P,S to monitor save area $45-$49
MONZ                 = $FF65             ; Monitor entry (clear stack, print '*', GETLN, parse)

; -- Mid-instruction references (6502 "skip" idiom; shown inline as cover+offset) --
;   $0A0E -> PRENIBBLE_LOOP2+1   enters the operand of the BIT at $0A0D (skips the LDX once)
;   $0F3E -> RWTS_FINISH+1       enters the operand of the BIT at $0F3D (clears C / loads A=0)

.org $0800

; [AI] Byte $0800 is the stage-1 hand-off scratch (sector data, not executed); stage 1 JMPs $0801.
        .byte   $01                                              ; $0800

; ---------------------------------------------------------------------------
; BOOT_RELOC -- relocating stage-2 entry.
; [AI] On first entry the disk controller left the boot slot number in X (slot*16) and a
;       page count in $27. The very first pass ($27 == 9) derives the controller's $Cn page
;       from X (>>4 | $C0), then seeds the indirect-JMP pointer at $3E/$3F = $0E5C..-style
;       reentry so each subsequent pass copies one more page of the loader into place and
;       re-enters via JMP ($003E). After 11 pages ($00 reaches $0B) it transfers to POST_LOAD
;       at $1000.
; ---------------------------------------------------------------------------
BOOT_RELOC:
        LDA $27                      ; $0801  A5 27   pass counter
        CMP #$09                     ; $0803  C9 09   first pass?
        BNE RELOC_NEXT               ; $0805  D0 13
        TXA                          ; $0807  8A      X = boot slot * 16
        LSR                          ; $0808  4A
        LSR                          ; $0809  4A
        LSR                          ; $080A  4A
        LSR                          ; $080B  4A
        ORA #$C0                     ; $080C  09 C0   -> $Cn high byte of boot firmware page
        STA $3F                      ; $080E  85 3F
        LDA #$5C                     ; $0810  A9 5C
        STA $3E                      ; $0812  85 3E   $3E/$3F = $Cn5C reentry vector
        LDA #$00                     ; $0814  A9 00
        STA $00                      ; $0816  85 00   page counter := 0
        INC $27                      ; $0818  E6 27
RELOC_NEXT:
        INC $00                      ; $081A  E6 00
        LDY $00                      ; $081C  A4 00
        CPY #$0B                     ; $081E  C0 0B   copied all 11 pages?
        BNE RELOC_STEP               ; $0820  D0 03
        JMP POST_LOAD                ; $0822  4C 00 10  done relocating -> install/boot
RELOC_STEP:
        LDA SKEW_TABLE,Y             ; $0825  B9 2D 08
        STA $3D                      ; $0828  85 3D
        JMP (A2L)                    ; $082A  6C 3E 00  re-enter loader via relocated vector

; [AI] SKEW_TABLE: DOS-3.3 physical->logical sector interleave (00 02 04 06 08 0A 0C 0E 01 ...).
SKEW_TABLE:
        .byte   $00, $02, $04, $06, $08, $0A, $0C, $0E, $01, $03, $05, $07, $09, $0B, $0D, $0F ; $082D
; [AI] ASCII copyright string (high bit set): " COPYRIGHT (C) 1980 MICROSOFT - NK ".
        ASCHI   " COPYRIGHT (C) 1980 MICROSOFT - NK "            ; $083D
        .res    160, $FF    ; $0860  fill (unused tail of the boot sector)
        .res    256, $00    ; $0900  primary nibble buffer page ($0900-$09FF), zeroed image on disk

; ---------------------------------------------------------------------------
; PRENIBBLE -- 6-and-2 encode pre-pass (write path).
; [AI] Splits the 256-byte data buffer at ($3E) into the high-6-bits stream in $0900 and the
;       low-2-bits ("aux") stream in $0D00, ready for WRITE_SECTOR to nibblize and emit.
; ---------------------------------------------------------------------------
PRENIBBLE:
        LDX #$55                     ; $0A00  A2 55
        LDA #$00                     ; $0A02  A9 00
PRENIBBLE_CLR:
        STA $0D00,X                  ; $0A04  9D 00 0D  clear the 0x56-byte aux buffer
        DEX                          ; $0A07  CA
        BPL PRENIBBLE_CLR            ; $0A08  10 FA
        TAY                          ; $0A0A  A8
        LDX #$AC                     ; $0A0B  A2 AC
PRENIBBLE_LOOP2:
        BIT $AAA2                    ; $0A0D  2C A2 AA  (also the LDX #$AA / 2C skip target at +1)
PRENIBBLE_LOOP:
        DEY                          ; $0A10  88
        LDA ($3E),Y                  ; $0A11  B1 3E
        LSR                          ; $0A13  4A
        ROL PRENIB_ROL_CELLS,X       ; $0A14  3E 56 0C  (aux nibble built in $0C56-overlapping region; see note)
        LSR                          ; $0A17  4A
        ROL PRENIB_ROL_CELLS,X       ; $0A18  3E 56 0C
        STA $0900,Y                  ; $0A1B  99 00 09
        INX                          ; $0A1E  E8
        BNE PRENIBBLE_LOOP           ; $0A1F  D0 EF
        TYA                          ; $0A21  98
        BNE PRENIBBLE_LOOP2+1        ; $0A22  D0 EA
        RTS                          ; $0A24  60

; ---------------------------------------------------------------------------
; WRITE_SECTOR -- write one 6-and-2 encoded data field.
; [AI] Emits the address sync ($D5 $AA $AD prologue), the 342 data nibbles from the $0900/$0D00
;       buffers translated through WRITE_NIB_TABLE, the running checksum, then the epilogue
;       ($DE $AA $EB $FF). X = slot*16. Falls into WR_NIB / WR_NIB_RAW helpers below.
; ---------------------------------------------------------------------------
WRITE_SECTOR:
        SEC                          ; $0A25  38
        STX $27                      ; $0A26  86 27
        STX SCRN_HOLE_0678_S0        ; $0A28  8E 78 06
        LDA $C08D,X                  ; $0A2B  BD 8D C0  Q6L/Q7 sequence: arm write
        LDA $C08E,X                  ; $0A2E  BD 8E C0
        BMI WRITE_PROT               ; $0A31  30 7C     write-protected? bail
        LDA $0D00                    ; $0A33  AD 00 0D
        STA $26                      ; $0A36  85 26     seed checksum
        LDA #$FF                     ; $0A38  A9 FF
        STA $C08F,X                  ; $0A3A  9D 8F C0
        ORA $C08C,X                  ; $0A3D  1D 8C C0  shift the $FF sync byte
        PHA                          ; $0A40  48
        PLA                          ; $0A41  68
        NOP                          ; $0A42  EA
        LDY #$04                     ; $0A43  A0 04
WRITE_SYNC:
        PHA                          ; $0A45  48
        PLA                          ; $0A46  68
        JSR WR_NIB_RAW               ; $0A47  20 B5 0A  write 4 self-sync $FF bytes
        DEY                          ; $0A4A  88
        BNE WRITE_SYNC               ; $0A4B  D0 F8
        LDA #$D5                     ; $0A4D  A9 D5
        JSR WR_NIB                   ; $0A4F  20 B4 0A  data-field prologue $D5
        LDA #$AA                     ; $0A52  A9 AA
        JSR WR_NIB                   ; $0A54  20 B4 0A  $AA
        LDA #$AD                     ; $0A57  A9 AD
        JSR WR_NIB                   ; $0A59  20 B4 0A  $AD
        TYA                          ; $0A5C  98
        LDY #$56                     ; $0A5D  A0 56
        BNE WRITE_AUX_GO             ; $0A5F  D0 03
WRITE_AUX:
        LDA $0D00,Y                  ; $0A61  B9 00 0D  aux (2-bit) nibbles
WRITE_AUX_GO:
        EOR $0CFF,Y                  ; $0A64  59 FF 0C
        TAX                          ; $0A67  AA
        LDA WRITE_NIB_TABLE,X        ; $0A68  BD 56 0D
        LDX $27                      ; $0A6B  A6 27
        STA $C08D,X                  ; $0A6D  9D 8D C0
        LDA $C08C,X                  ; $0A70  BD 8C C0
        DEY                          ; $0A73  88
        BNE WRITE_AUX                ; $0A74  D0 EB
        LDA $26                      ; $0A76  A5 26
        NOP                          ; $0A78  EA
WRITE_DATA:
        EOR $0900,Y                  ; $0A79  59 00 09  high-6-bit nibbles
        TAX                          ; $0A7C  AA
        LDA WRITE_NIB_TABLE,X        ; $0A7D  BD 56 0D
        LDX SCRN_HOLE_0678_S0        ; $0A80  AE 78 06
        STA $C08D,X                  ; $0A83  9D 8D C0
        LDA $C08C,X                  ; $0A86  BD 8C C0
        LDA $0900,Y                  ; $0A89  B9 00 09
        INY                          ; $0A8C  C8
        BNE WRITE_DATA               ; $0A8D  D0 EA
        TAX                          ; $0A8F  AA
        LDA WRITE_NIB_TABLE,X        ; $0A90  BD 56 0D  checksum nibble
        LDX $27                      ; $0A93  A6 27
        JSR WR_NIB_RAW2              ; $0A95  20 B7 0A
        LDA #$DE                     ; $0A98  A9 DE
        JSR WR_NIB                   ; $0A9A  20 B4 0A  epilogue $DE
        LDA #$AA                     ; $0A9D  A9 AA
        JSR WR_NIB                   ; $0A9F  20 B4 0A  $AA
        LDA #$EB                     ; $0AA2  A9 EB
        JSR WR_NIB                   ; $0AA4  20 B4 0A  $EB
        LDA #$FF                     ; $0AA7  A9 FF
        JSR WR_NIB                   ; $0AA9  20 B4 0A  trailing $FF
        LDA $C08E,X                  ; $0AAC  BD 8E C0  back to read mode
WRITE_PROT:
        LDA $C08C,X                  ; $0AAF  BD 8C C0
        RTS                          ; $0AB2  60
        .byte   $EA                                              ; $0AB3  (alignment NOP, not reached)

; [AI] WR_NIB / WR_NIB_RAW / WR_NIB_RAW2: write one byte A to the drive with the standard
;       4us inter-byte timing (PHA/PLA pad). Entry points clear carry / skip the pad as needed.
WR_NIB:
        CLC                          ; $0AB4  18
WR_NIB_RAW:
        PHA                          ; $0AB5  48
        PLA                          ; $0AB6  68
WR_NIB_RAW2:
        STA $C08D,X                  ; $0AB7  9D 8D C0
        ORA $C08C,X                  ; $0ABA  1D 8C C0
        RTS                          ; $0ABD  60
        .res    66, $FF    ; $0ABE  fill

; ---------------------------------------------------------------------------
; READ_DATA -- find and read one 6-and-2 data field into the nibble buffers.
; [AI] Spins on the data prologue $D5 $AA $AD, reads the 0x56 aux nibbles then 0x100 data
;       nibbles (denibblizing through the running checksum into $0D00 then $0900), and verifies
;       the trailing checksum + $DE $AA epilogue. Returns C=0 on success, C=1 (via READ_FAIL)
;       on any mismatch. X = slot*16.
; ---------------------------------------------------------------------------
READ_DATA:
        LDY #$20                     ; $0B00  A0 20   prologue search retry budget
READ_DATA_RETRY:
        DEY                          ; $0B02  88
        BEQ READ_FAIL                ; $0B03  F0 63
READ_D5:
        LDA $C08C,X                  ; $0B05  BD 8C C0
        BPL READ_D5                  ; $0B08  10 FB
READ_CMP_D5:
        EOR #$D5                     ; $0B0A  49 D5
        BNE READ_DATA_RETRY          ; $0B0C  D0 F4
        NOP                          ; $0B0E  EA
READ_AA1:
        LDA $C08C,X                  ; $0B0F  BD 8C C0
        BPL READ_AA1                 ; $0B12  10 FB
        CMP #$AA                     ; $0B14  C9 AA
        BNE READ_CMP_D5              ; $0B16  D0 F2
        LDY #$56                     ; $0B18  A0 56
READ_AD:
        LDA $C08C,X                  ; $0B1A  BD 8C C0
        BPL READ_AD                  ; $0B1D  10 FB
        CMP #$AD                     ; $0B1F  C9 AD   data prologue is $D5 $AA $AD
        BNE READ_CMP_D5              ; $0B21  D0 E7
        NOP                          ; $0B23  EA
        NOP                          ; $0B24  EA
        LDA #$00                     ; $0B25  A9 00
READ_AUX_LOOP:
        DEY                          ; $0B27  88
        STY $26                      ; $0B28  84 26
READ_AUX_NIB:
        LDY $C08C,X                  ; $0B2A  BC 8C C0
        BPL READ_AUX_NIB             ; $0B2D  10 FB
        EOR $0D00,Y                  ; $0B2F  59 00 0D  denibblize through read-translate (in $0D00)
        LDY $26                      ; $0B32  A4 26
        STA $0D00,Y                  ; $0B34  99 00 0D
        BNE READ_AUX_LOOP            ; $0B37  D0 EE
READ_DATA_LOOP:
        STY $26                      ; $0B39  84 26
READ_DATA_NIB:
        LDY $C08C,X                  ; $0B3B  BC 8C C0
        BPL READ_DATA_NIB            ; $0B3E  10 FB
        EOR $0D00,Y                  ; $0B40  59 00 0D
        LDY $26                      ; $0B43  A4 26
        STA $0900,Y                  ; $0B45  99 00 09  primary (high-6-bit) stream into $0900
        INY                          ; $0B48  C8
        BNE READ_DATA_LOOP           ; $0B49  D0 EE
READ_CSUM:
        LDY $C08C,X                  ; $0B4B  BC 8C C0
        BPL READ_CSUM                ; $0B4E  10 FB
        CMP $0D00,Y                  ; $0B50  D9 00 0D  final checksum must equal accumulator
        BNE READ_FAIL                ; $0B53  D0 13
READ_DE:
        LDA $C08C,X                  ; $0B55  BD 8C C0
        BPL READ_DE                  ; $0B58  10 FB
        CMP #$DE                     ; $0B5A  C9 DE   epilogue $DE
        BNE READ_FAIL                ; $0B5C  D0 0A
        NOP                          ; $0B5E  EA
READ_EPI_AA:
        LDA $C08C,X                  ; $0B5F  BD 8C C0
        BPL READ_EPI_AA              ; $0B62  10 FB
        CMP #$AA                     ; $0B64  C9 AA   epilogue $AA
        BEQ READ_ADDR_OK             ; $0B66  F0 5C   shared success exit (CLC/RTS at $0BC4)
READ_FAIL:
        SEC                          ; $0B68  38
        RTS                          ; $0B69  60

; ---------------------------------------------------------------------------
; READ_ADDRESS -- find and read one address field ($D5 $AA $96 prologue).
; [AI] 4-and-4 decodes volume/track/sector/checksum into $2A..$2D, validating the $DE $AA
;       epilogue. C=0 on success. X = slot*16.
; ---------------------------------------------------------------------------
READ_ADDRESS:
        LDY #$FC                     ; $0B6A  A0 FC
        STY $26                      ; $0B6C  84 26   retry counter ($26FC..)
READ_ADDR_SPIN:
        INY                          ; $0B6E  C8
        BNE READ_ADDR_D5             ; $0B6F  D0 04
        INC $26                      ; $0B71  E6 26
        BEQ READ_FAIL                ; $0B73  F0 F3   ran out of retries
READ_ADDR_D5:
        LDA $C08C,X                  ; $0B75  BD 8C C0
        BPL READ_ADDR_D5             ; $0B78  10 FB
READ_ADDR_CMP_D5:
        CMP #$D5                     ; $0B7A  C9 D5
        BNE READ_ADDR_SPIN           ; $0B7C  D0 F0
        NOP                          ; $0B7E  EA
READ_ADDR_AA:
        LDA $C08C,X                  ; $0B7F  BD 8C C0
        BPL READ_ADDR_AA             ; $0B82  10 FB
        CMP #$AA                     ; $0B84  C9 AA
        BNE READ_ADDR_CMP_D5         ; $0B86  D0 F2
        LDY #$03                     ; $0B88  A0 03   read 4 fields (vol/trk/sec/csum)
READ_ADDR_96:
        LDA $C08C,X                  ; $0B8A  BD 8C C0
        BPL READ_ADDR_96             ; $0B8D  10 FB
        CMP #$96                     ; $0B8F  C9 96   address prologue is $D5 $AA $96
        BNE READ_ADDR_CMP_D5         ; $0B91  D0 E7
        LDA #$00                     ; $0B93  A9 00
READ_ADDR_FIELD:
        STA $27                      ; $0B95  85 27
READ_ADDR_ODD:
        LDA $C08C,X                  ; $0B97  BD 8C C0
        BPL READ_ADDR_ODD            ; $0B9A  10 FB
        ROL                          ; $0B9C  2A      odd bits
        STA $26                      ; $0B9D  85 26
READ_ADDR_EVEN:
        LDA $C08C,X                  ; $0B9F  BD 8C C0
        BPL READ_ADDR_EVEN           ; $0BA2  10 FB
        AND $26                      ; $0BA4  25 26   merge even+odd -> 4&4 decode
        STA H2,Y                     ; $0BA6  99 2C 00  store into $2C+Y ($2C..$2F field)
        EOR $27                      ; $0BA9  45 27
        DEY                          ; $0BAB  88
        BPL READ_ADDR_FIELD          ; $0BAC  10 E7
        TAY                          ; $0BAE  A8
        BNE READ_FAIL                ; $0BAF  D0 B7   checksum nonzero -> fail
READ_ADDR_DE:
        LDA $C08C,X                  ; $0BB1  BD 8C C0
        BPL READ_ADDR_DE             ; $0BB4  10 FB
        CMP #$DE                     ; $0BB6  C9 DE
        BNE READ_FAIL                ; $0BB8  D0 AE
        NOP                          ; $0BBA  EA
READ_ADDR_EPI_AA:
        LDA $C08C,X                  ; $0BBB  BD 8C C0
        BPL READ_ADDR_EPI_AA         ; $0BBE  10 FB
        CMP #$AA                     ; $0BC0  C9 AA
        BNE READ_FAIL                ; $0BC2  D0 A4
READ_ADDR_OK:
        CLC                          ; $0BC4  18
        RTS                          ; $0BC5  60

; ---------------------------------------------------------------------------
; POSTNIBBLE -- 6-and-2 decode (read path): rebuild the 256-byte data buffer at ($3E)
; [AI] from the $0900 (high-6) and $0D00 (low-2 aux) nibble streams READ_DATA filled.
; ---------------------------------------------------------------------------
POSTNIBBLE:
        LDY #$00                     ; $0BC6  A0 00
POSTNIB_OUTER:
        LDX #$56                     ; $0BC8  A2 56
POSTNIB_INNER:
        DEX                          ; $0BCA  CA
        BMI POSTNIB_OUTER            ; $0BCB  30 FB
        LDA $0900,Y                  ; $0BCD  B9 00 09
        LSR $0D00,X                  ; $0BD0  5E 00 0D  pull the low 2 bits from the aux stream
        ROL                          ; $0BD3  2A
        LSR $0D00,X                  ; $0BD4  5E 00 0D
        ROL                          ; $0BD7  2A
        STA ($3E),Y                  ; $0BD8  91 3E
        INY                          ; $0BDA  C8
        BNE POSTNIB_INNER            ; $0BDB  D0 ED
        RTS                          ; $0BDD  60

; ---------------------------------------------------------------------------
; SEEK -- step the head from the current track to the target track.
; [AI] Entered (via JMP at PHASE_DRIVE end) with A = destination track in $2A and the current
;       track in $0478. Phases the arm one half-track at a time using the on/off step-time
;       tables ($0C50 / $0C5C), then settles. X/$2B = slot*16.
; ---------------------------------------------------------------------------
SEEK:
        STX $2B                      ; $0BDE  86 2B
        STA $2A                      ; $0BE0  85 2A   destination track
        CMP SCRN_HOLE_0478_S0        ; $0BE2  CD 78 04  already there?
        BEQ PHASE_OFF_RTS            ; $0BE5  F0 53
        LDA #$00                     ; $0BE7  A9 00
        STA $26                      ; $0BE9  85 26   step index
SEEK_STEP:
        LDA SCRN_HOLE_0478_S0        ; $0BEB  AD 78 04  current track
        STA $27                      ; $0BEE  85 27
        SEC                          ; $0BF0  38
        SBC $2A                      ; $0BF1  E5 2A
        BEQ SEEK_DONE                ; $0BF3  F0 33   reached destination
        BCS SEEK_OUT                 ; $0BF5  B0 07   step outward
        EOR #$FF                     ; $0BF7  49 FF
        INC SCRN_HOLE_0478_S0        ; $0BF9  EE 78 04  step inward
        BCC SEEK_DIST                ; $0BFC  90 05
SEEK_OUT:
        ADC #$FE                     ; $0BFE  69 FE
        DEC SCRN_HOLE_0478_S0        ; $0C00  CE 78 04
SEEK_DIST:
        CMP $26                      ; $0C03  C5 26
        BCC SEEK_USE_IDX             ; $0C05  90 02
        LDA $26                      ; $0C07  A5 26
SEEK_USE_IDX:
        CMP #$0C                     ; $0C09  C9 0C   clamp step index to table size
        BCS SEEK_CLAMP               ; $0C0B  B0 01
        TAY                          ; $0C0D  A8
SEEK_CLAMP:
        SEC                          ; $0C0E  38
        JSR PHASE_ON_CUR             ; $0C0F  20 2C 0C  energize phase for current track
        LDA TIME_ON_TABLE,Y          ; $0C12  B9 50 0C
        JSR WAIT                     ; $0C15  20 3B 0C
        LDA $27                      ; $0C18  A5 27
        CLC                          ; $0C1A  18
        JSR PHASE_OFF                ; $0C1B  20 2F 0C  de-energize previous phase
        LDA TIME_OFF_TABLE,Y         ; $0C1E  B9 5C 0C
        JSR WAIT                     ; $0C21  20 3B 0C
        INC $26                      ; $0C24  E6 26
        BNE SEEK_STEP                ; $0C26  D0 C3
SEEK_DONE:
        JSR WAIT                     ; $0C28  20 3B 0C  final settle
        CLC                          ; $0C2B  18

; [AI] PHASE_ON_CUR / PHASE_OFF: turn a stepper phase on (carry set) or off (carry clear).
;       The phase index = (track & 3)*2 + carry, written to $C080+slot*16+index.
PHASE_ON_CUR:
        LDA SCRN_HOLE_0478_S0        ; $0C2C  AD 78 04
PHASE_OFF:
        AND #$03                     ; $0C2F  29 03
        ROL                          ; $0C31  2A
        ORA $2B                      ; $0C32  05 2B   | slot*16
        TAX                          ; $0C34  AA
        LDA LC_RAM_BANK2_RD,X        ; $0C35  BD 80 C0  $C080+X -> phase magnet on/off
        LDX $2B                      ; $0C38  A6 2B
PHASE_OFF_RTS:
        RTS                          ; $0C3A  60

; [AI] WAIT: the $FCA8-style nested countdown. Outer count in A, plus a 16-bit decrement of
;       $46/$47 each pass, used both for phase-step timing and motor-on settle.
WAIT:
        LDX #$11                     ; $0C3B  A2 11
WAIT_INNER:
        DEX                          ; $0C3D  CA
        BNE WAIT_INNER               ; $0C3E  D0 FD
        INC $46                      ; $0C40  E6 46
        BNE WAIT_DEC                 ; $0C42  D0 06
        INC $47                      ; $0C44  E6 47
        BNE WAIT_DEC                 ; $0C46  D0 02
        DEC $47                      ; $0C48  C6 47
WAIT_DEC:
        SEC                          ; $0C4A  38
        SBC #$01                     ; $0C4B  E9 01
        BNE WAIT                     ; $0C4D  D0 EC
        RTS                          ; $0C4F  60

; [AI] Arm-step phase-time tables (indexed by clamped step distance).
TIME_ON_TABLE:
        .byte   $01, $30, $28, $24, $20, $1E                     ; $0C50  on-times
PRENIB_ROL_CELLS:
        .byte   $1D, $1C, $1C, $1C, $1C, $1C                     ; $0C56  (only touched by PRENIBBLE's ROL aux build)
TIME_OFF_TABLE:
        .byte   $70, $2C, $26, $22, $1F, $1E, $1D, $1C, $1C, $1C, $1C, $1C ; $0C5C  arm-step off-times
        .res    238, $FF    ; $0C68  fill

; [AI] WRITE_NIB_TABLE: 6-and-2 write-translate table -- maps 6-bit code -> on-disk byte
;       ($96,$97,$9A,...$FF), the classic "valid disk byte" set (>=2 transitions, no run of 3
;       zero bits). READ_DATA uses the same region via the running EOR to invert it.
WRITE_NIB_TABLE:
        .byte   $96, $97, $9A, $9B, $9D, $9E, $9F, $A6, $A7, $AB, $AC, $AD, $AE, $AF, $B2, $B3 ; $0D56
        .byte   $B4, $B5, $B6, $B7, $B9, $BA, $BB, $BC, $BD, $BE, $BF, $CB, $CD, $CE, $CF, $D3 ; $0D66
        .byte   $D6, $D7, $D9, $DA, $DB, $DC, $DD, $DE, $DF, $E5, $E6, $E7, $E9, $EA, $EB, $EC ; $0D76
        .byte   $ED, $EE, $EF, $F2, $F3, $F4, $F5, $F6, $F7, $F9, $FA, $FB, $FC, $FD, $FE, $FF ; $0D86
; [AI] Interleaved with the table is the read-translate (inverse) map used to denibblize.
        .byte   $00, $01, $98, $99, $02, $03, $9C, $04, $05, $06, $A0, $A1, $A2, $A3, $A4, $A5 ; $0D96
        .byte   $07, $08, $A8, $A9, $AA, $09, $0A, $0B, $0C, $0D, $B0, $B1, $0E, $0F, $10, $11 ; $0DA6
        .byte   $12, $13, $B8, $14, $15, $16, $17, $18, $19, $1A, $C0, $C1, $C2, $C3, $C4, $C5 ; $0DB6
        .byte   $C6, $C7, $C8, $C9, $CA, $1B, $CC, $1C, $1D, $1E, $D0, $D1, $D2, $1F, $D4, $D5 ; $0DC6
        .byte   $20, $21, $D8, $22, $23, $24, $25, $26, $27, $28, $E0, $E1, $E2, $E3, $E4, $29 ; $0DD6
        .byte   $2A, $2B, $E8, $2C, $2D, $2E, $2F, $30, $31, $32, $F0, $F1, $33, $34, $35, $36 ; $0DE6
        .byte   $37, $38, $F8, $39, $3A, $3B, $3C, $3D, $3E, $3F ; $0DF6

; ---------------------------------------------------------------------------
; RWTS_REINIT -- restart the whole load (jumps to LOAD_CPM).
; ---------------------------------------------------------------------------
RWTS_REINIT:
        JMP LOAD_CPM                 ; $0E00  4C AD 0F

; ---------------------------------------------------------------------------
; RWTS_LC_WRAP -- language-card-banked wrapper around RWTS_ENGINE.
; [AI] Selects LC RAM bank 2 read/write, runs one sector with interrupts off, restores ROM.
;       Not reached on the traced cold-boot path (no caller in this build's 6502 image);
;       present as a callable RWTS entry for the running system after relocation.
; ---------------------------------------------------------------------------
RWTS_LC_WRAP:
        LDA LC_RAM_BANK2_RDWR        ; $0E03  AD 83 C0
        PHP                          ; $0E06  08
        SEI                          ; $0E07  78
        JSR RWTS_ENGINE              ; $0E08  20 10 0E
        LDA LC_ROM_BANK2_WR          ; $0E0B  AD 81 C0
        PLP                          ; $0E0E  28
        RTS                          ; $0E0F  60

; ---------------------------------------------------------------------------
; RWTS_ENGINE -- read / write / seek dispatcher (the core of this private RWTS).
; [AI] Driven by the $03E0-$03EB parameter block. Selects the drive ($03E6/$03E7 pair),
;       spins it up, sets the data buffer pointer from $03E8/$03E9, seeks to track $03E4,
;       then loops scanning address fields until the wanted sector ($03E1 via the skew table
;       at $0F9D) is found and READ_DATA / WRITE_SECTOR completes. Returns C=0 ok, C=1 error.
; ---------------------------------------------------------------------------
RWTS_ENGINE:
        LDY #$02                     ; $0E10  A0 02
        STY SCRN_HOLE_06F8_S0        ; $0E12  8C F8 06  outer retry budget
        LDY #$04                     ; $0E15  A0 04
        STY SCRN_HOLE_04F8_S0        ; $0E17  8C F8 04  inner retry budget
        LDA $03E6                    ; $0E1A  AD E6 03  drive A select index
        TAX                          ; $0E1D  AA
        CMP $03E7                    ; $0E1E  CD E7 03  same as last drive?
        BEQ ENG_MOTOR_ON             ; $0E21  F0 1D
        TXA                          ; $0E23  8A      drive changed: spin the new one up
        TAY                          ; $0E24  A8
        LDA $03E7                    ; $0E25  AD E7 03
        TAX                          ; $0E28  AA
        TYA                          ; $0E29  98
        PHA                          ; $0E2A  48
        STA $03E7                    ; $0E2B  8D E7 03
        LDA $C08E,X                  ; $0E2E  BD 8E C0
ENG_SPIN_WAIT:
        LDY #$08                     ; $0E31  A0 08
        LDA $C08C,X                  ; $0E33  BD 8C C0
ENG_SPIN_LOOP:
        CMP $C08C,X                  ; $0E36  DD 8C C0  wait for the disk to spin up (data toggling)
        BNE ENG_SPIN_WAIT            ; $0E39  D0 F6
        DEY                          ; $0E3B  88
        BNE ENG_SPIN_LOOP            ; $0E3C  D0 F8
        PLA                          ; $0E3E  68
        TAX                          ; $0E3F  AA
ENG_MOTOR_ON:
        LDA $C08E,X                  ; $0E40  BD 8E C0  Q7L (read), motor on
        LDA $C08C,X                  ; $0E43  BD 8C C0
        LDY #$08                     ; $0E46  A0 08
ENG_SETTLE:
        LDA $C08C,X                  ; $0E48  BD 8C C0
        PHA                          ; $0E4B  48
        PLA                          ; $0E4C  68
        PHA                          ; $0E4D  48
        PLA                          ; $0E4E  68
        STX SCRN_HOLE_05F8_S0        ; $0E4F  8E F8 05  save the drive's slot*16 index
        CMP $C08C,X                  ; $0E52  DD 8C C0
        BNE ENG_SETUP                ; $0E55  D0 03
        DEY                          ; $0E57  88
        BNE ENG_SETTLE               ; $0E58  D0 EE
ENG_SETUP:
        PHP                          ; $0E5A  08
        LDA LC_ROM_BANK1_WR,X        ; $0E5B  BD 89 C0  (read-twice arm for the LC sequence below)
        LDA $03E8                    ; $0E5E  AD E8 03
        STA $3E                      ; $0E61  85 3E    buffer pointer lo
        LDA $03E9                    ; $0E63  AD E9 03
        STA $3F                      ; $0E66  85 3F    buffer pointer hi
        LDA #$EF                     ; $0E68  A9 EF
        STA $46                      ; $0E6A  85 46    WAIT 16-bit base = $D8EF
        LDA #$D8                     ; $0E6C  A9 D8
        STA $47                      ; $0E6E  85 47
        LDA $03E4                    ; $0E70  AD E4 03  destination track
        CMP $03E5                    ; $0E73  CD E5 03  changed since last op?
        BEQ ENG_NO_RECAL             ; $0E76  F0 07
        STA $03E5                    ; $0E78  8D E5 03
        PLP                          ; $0E7B  28
        LDY #$00                     ; $0E7C  A0 00
        PHP                          ; $0E7E  08
ENG_NO_RECAL:
        ROR                          ; $0E7F  6A      bit0 -> LC bank select for buffer below
        BCC ENG_LC_RAM               ; $0E80  90 05
        LDA LC_ROM_RD2,X             ; $0E82  BD 8A C0
        BCS ENG_LC_DONE              ; $0E85  B0 03
ENG_LC_RAM:
        LDA LC_RAM_BANK1_RDWR,X      ; $0E87  BD 8B C0
ENG_LC_DONE:
        ROR $35                      ; $0E8A  66 35    remember bank bit in $35.7
        PLP                          ; $0E8C  28
        PHP                          ; $0E8D  08
        BNE ENG_HAVE_TRACK           ; $0E8E  D0 0B
        LDY #$07                     ; $0E90  A0 07
ENG_RECAL:
        JSR WAIT                     ; $0E92  20 3B 0C  recalibrate settle
        DEY                          ; $0E95  88
        BNE ENG_RECAL                ; $0E96  D0 FA
        LDX SCRN_HOLE_05F8_S0        ; $0E98  AE F8 05
ENG_HAVE_TRACK:
        LDA $03E0                    ; $0E9B  AD E0 03  command -> select track via PHASE_DRIVE
        JSR PHASE_DRIVE              ; $0E9E  20 52 0F
        LDA $03EB                    ; $0EA1  AD EB 03  mode byte
        PLP                          ; $0EA4  28
        BNE ENG_FIND_SECTOR          ; $0EA5  D0 11
        CMP #$01                     ; $0EA7  C9 01
        BEQ ENG_FIND_SECTOR          ; $0EA9  F0 0D
ENG_HOLD:
        LDY #$12                     ; $0EAB  A0 12
ENG_HOLD_INNER:
        DEY                          ; $0EAD  88
        BNE ENG_HOLD_INNER           ; $0EAE  D0 FD
        INC $46                      ; $0EB0  E6 46
        BNE ENG_HOLD                 ; $0EB2  D0 F7
        INC $47                      ; $0EB4  E6 47
        BNE ENG_HOLD                 ; $0EB6  D0 F3
ENG_FIND_SECTOR:
        ROR                          ; $0EB8  6A
        PHP                          ; $0EB9  08      carry = write?
        BCS ENG_SCAN                 ; $0EBA  B0 03
        JSR PRENIBBLE                ; $0EBC  20 00 0A  (write path) prep nibble buffers first
ENG_SCAN:
        LDY #$30                     ; $0EBF  A0 30    address-scan retry budget
        STY SCRN_HOLE_0578_S0        ; $0EC1  8C 78 05
ENG_SCAN_LOOP:
        LDX SCRN_HOLE_05F8_S0        ; $0EC4  AE F8 05
        JSR READ_ADDRESS             ; $0EC7  20 6A 0B
        BCC ENG_GOT_ADDR             ; $0ECA  90 24
ENG_RETRY:
        DEC SCRN_HOLE_0578_S0        ; $0ECC  CE 78 05
        BPL ENG_SCAN_LOOP            ; $0ECF  10 F3
ENG_RESEEK:
        LDA SCRN_HOLE_0478_S0        ; $0ED1  AD 78 04  lost: re-seek and retry
        PHA                          ; $0ED4  48
        LDA #$60                     ; $0ED5  A9 60
        JSR ARM_MOVE                 ; $0ED7  20 84 0F
        DEC SCRN_HOLE_06F8_S0        ; $0EDA  CE F8 06  exhaust outer retries
        BEQ ENG_GIVE_UP              ; $0EDD  F0 28
        LDA #$04                     ; $0EDF  A9 04
        STA SCRN_HOLE_04F8_S0        ; $0EE1  8D F8 04
        LDA #$00                     ; $0EE4  A9 00
        JSR PHASE_DRIVE              ; $0EE6  20 52 0F
        PLA                          ; $0EE9  68
ENG_RESEEK2:
        JSR PHASE_DRIVE              ; $0EEA  20 52 0F
        JMP ENG_SCAN                 ; $0EED  4C BF 0E
ENG_GOT_ADDR:
        LDY $2E                      ; $0EF0  A4 2E    track from the address field
        CPY SCRN_HOLE_0478_S0        ; $0EF2  CC 78 04  on the right track?
        BEQ ENG_RIGHT_TRACK          ; $0EF5  F0 19
        LDA SCRN_HOLE_0478_S0        ; $0EF7  AD 78 04  wrong track: correct the arm
        PHA                          ; $0EFA  48
        TYA                          ; $0EFB  98
        JSR ARM_MOVE                 ; $0EFC  20 84 0F
        PLA                          ; $0EFF  68
        DEC SCRN_HOLE_04F8_S0        ; $0F00  CE F8 04
        BNE ENG_RESEEK2              ; $0F03  D0 E5
        BEQ ENG_RESEEK               ; $0F05  F0 CA
ENG_GIVE_UP:
        PLA                          ; $0F07  68
        LDA #$40                     ; $0F08  A9 40    error code $40
ENG_ERR_EXIT:
        PLP                          ; $0F0A  28
        JMP RWTS_FINISH+1            ; $0F0B  4C 3E 0F  (enters BIT operand: A preserved, set result)
        .byte   $F0, $2A                                         ; $0F0E  (dead branch bytes; not reached)
ENG_RIGHT_TRACK:
        LDA $2F                      ; $0F10  A5 2F    sector from the address field
        STA DOSRWA                   ; $0F12  8D E3 03
        LDA $03E2                    ; $0F15  AD E2 03  wanted sector (0 = any)
        BEQ ENG_SECTOR_OK            ; $0F18  F0 08
        CMP $2F                      ; $0F1A  C5 2F
        BEQ ENG_SECTOR_OK            ; $0F1C  F0 04
        LDA #$20                     ; $0F1E  A9 20    sector mismatch code $20
        BNE ENG_ERR_EXIT             ; $0F20  D0 E8
ENG_SECTOR_OK:
        LDA $03E1                    ; $0F22  AD E1 03  logical sector index
        TAY                          ; $0F25  A8
        LDA SKEW_TABLE2,Y            ; $0F26  B9 9D 0F  map through interleave
        CMP $2D                      ; $0F29  C5 2D    matches physical sector?
        BNE ENG_RETRY                ; $0F2B  D0 9F
        PLP                          ; $0F2D  28
        BCC ENG_DO_READ              ; $0F2E  90 19
        JSR READ_DATA                ; $0F30  20 00 0B  (write path uses READ_DATA's buffers)
        PHP                          ; $0F33  08
        BCS ENG_RETRY                ; $0F34  B0 96
        PLP                          ; $0F36  28
        JSR POSTNIBBLE               ; $0F37  20 C6 0B
ENG_OK:
        CLC                          ; $0F3A  18
        LDA #$00                     ; $0F3B  A9 00    result 0 = success
RWTS_FINISH:
        BIT $38                      ; $0F3D  24 38    (its operand $38 is the SEC entered at +1)
        STA $03EA                    ; $0F3F  8D EA 03  store result code
        LDX SCRN_HOLE_05F8_S0        ; $0F42  AE F8 05
        LDA LC_RAM_BANK1_RD,X        ; $0F45  BD 88 C0  motor off (read RAM, write protect)
        RTS                          ; $0F48  60
ENG_DO_READ:
        JSR WRITE_SECTOR             ; $0F49  20 25 0A  (read cmd path actually writes; see param block)
        BCC ENG_OK                   ; $0F4C  90 EC
        LDA #$10                     ; $0F4E  A9 10    write error code $10
        BNE RWTS_FINISH+1            ; $0F50  D0 EC

; [AI] PHASE_DRIVE: high-level "move arm to (A) and pick the right LC bank" wrapper used by
;       the engine. Doubles A (track*2 = phase), calls ARM_STEP, then divides the tracking
;       cell back down. Tail-jumps into SEEK.
PHASE_DRIVE:
        ASL                          ; $0F52  0A
        JSR ARM_STEP                 ; $0F53  20 5A 0F
        LSR SCRN_HOLE_0478_S0        ; $0F56  4E 78 04
        RTS                          ; $0F59  60
ARM_STEP:
        STA $2E                      ; $0F5A  85 2E
        JSR SLOT_TO_Y                ; $0F5C  20 7D 0F
        LDA SCRN_HOLE_0478_S0,Y      ; $0F5F  B9 78 04
        BIT $35                      ; $0F62  24 35    which LC bank?
        BMI ARM_STEP_1               ; $0F64  30 03
        LDA SCRN_HOLE_04F8_S0,Y      ; $0F66  B9 F8 04
ARM_STEP_1:
        STA SCRN_HOLE_0478_S0        ; $0F69  8D 78 04
        LDA $2E                      ; $0F6C  A5 2E
        BIT $35                      ; $0F6E  24 35
        BMI ARM_STEP_2               ; $0F70  30 05
        STA SCRN_HOLE_04F8_S0,Y      ; $0F72  99 F8 04
        BPL ARM_STEP_3               ; $0F75  10 03
ARM_STEP_2:
        STA SCRN_HOLE_0478_S0,Y      ; $0F77  99 78 04
ARM_STEP_3:
        JMP SEEK                     ; $0F7A  4C DE 0B

; [AI] SLOT_TO_Y: Y := (X >> 4), i.e. slot*16 -> slot, an index into the per-drive cells.
SLOT_TO_Y:
        TXA                          ; $0F7D  8A
        LSR                          ; $0F7E  4A
        LSR                          ; $0F7F  4A
        LSR                          ; $0F80  4A
        LSR                          ; $0F81  4A
        TAY                          ; $0F82  A8
        RTS                          ; $0F83  60

; [AI] ARM_MOVE: stash A as target, fold in the LC-bank bit ($03E4 -> $35.7) and re-store the
;       per-drive tracking cell, used during re-seek correction.
ARM_MOVE:
        PHA                          ; $0F84  48
        LDA $03E4                    ; $0F85  AD E4 03
        ROR                          ; $0F88  6A
        ROR $35                      ; $0F89  66 35
        JSR SLOT_TO_Y                ; $0F8B  20 7D 0F
        PLA                          ; $0F8E  68
        ASL                          ; $0F8F  0A
        BIT $35                      ; $0F90  24 35
        BMI ARM_MOVE_1               ; $0F92  30 05
        STA SCRN_HOLE_04F8_S0,Y      ; $0F94  99 F8 04
        BPL ARM_MOVE_2               ; $0F97  10 03
ARM_MOVE_1:
        STA SCRN_HOLE_0478_S0,Y      ; $0F99  99 78 04
ARM_MOVE_2:
        RTS                          ; $0F9C  60

; [AI] SKEW_TABLE2: second copy of the physical->logical sector interleave (sector ordering).
SKEW_TABLE2:
        .byte   $00, $02, $04, $06, $08, $0A, $0C, $0E, $01, $03, $05, $07, $09, $0B, $0D, $0F ; $0F9D

; ---------------------------------------------------------------------------
; LOAD_CPM -- read the CP/M system image off the disk into RAM.
; [AI] Initializes the RWTS parameter block (drive A, start track $0B, $1C sectors) and loops
;       calling RWTS_ENGINE, advancing sector/track and the destination page ($03E9) each pass.
;       On any read error it prints ERR (PRERR) and restarts. Entered from RELOCATE_INSTALL
;       at the end of POST_LOAD as well, after self-patching its first read into a Z-80 vector.
; ---------------------------------------------------------------------------
LOAD_CPM:
        LDA #$E4                     ; $0FAD  A9 E4
        STA $03E9                    ; $0FAF  8D E9 03  destination page hi := $E4
        LDY #$00                     ; $0FB2  A0 00
        STY $03E8                    ; $0FB4  8C E8 03  destination page lo := 0
        STY $03E0                    ; $0FB7  8C E0 03  command := 0
        INY                          ; $0FBA  C8
        STY $03E4                    ; $0FBB  8C E4 03  track := 1 (becomes $0B below via $03E1)
        STY $03EB                    ; $0FBE  8C EB 03  mode := 1
        LDA #$60                     ; $0FC1  A9 60
        STA $03E6                    ; $0FC3  8D E6 03  drive-select seed
        LDA #$0B                     ; $0FC6  A9 0B
        STA $03E1                    ; $0FC8  8D E1 03  starting logical sector
        LDA #$1C                     ; $0FCB  A9 1C    sector count (0x1C)
LOAD_LOOP:
        PHA                          ; $0FCD  48
        PHP                          ; $0FCE  08
        SEI                          ; $0FCF  78
        JSR RWTS_ENGINE              ; $0FD0  20 10 0E
        BCC LOAD_OK                  ; $0FD3  90 08
        JSR PRERR                    ; $0FD5  20 2D FF  read error -> "ERR" + bell
        PLP                          ; $0FD8  28
        PLA                          ; $0FD9  68
        JMP LOAD_CPM                 ; $0FDA  4C AD 0F  ...and start over
LOAD_OK:
        PLP                          ; $0FDD  28
        INC $03E9                    ; $0FDE  EE E9 03  advance destination page
        LDX $03E1                    ; $0FE1  AE E1 03  advance logical sector
        INX                          ; $0FE4  E8
        CPX #$10                     ; $0FE5  E0 10    wrapped past sector 15?
        BNE LOAD_NEXT                ; $0FE7  D0 05
        LDX #$00                     ; $0FE9  A2 00
        INC $03E0                    ; $0FEB  EE E0 03  next track
LOAD_NEXT:
        STX $03E1                    ; $0FEE  8E E1 03
        PLA                          ; $0FF1  68
        SEC                          ; $0FF2  38
        SBC #$01                     ; $0FF3  E9 01    one fewer sector to go
        BNE LOAD_LOOP                ; $0FF5  D0 D6
        LDA #$08                     ; $0FF7  A9 08
        STA $03E9                    ; $0FF9  8D E9 03  reset destination page hi
        RTS                          ; $0FFC  60
        .byte   $FF, $FF                                         ; $0FFD  fill

; [AI] $0FFF is the landing slot for the 14-byte Z-80 vector template copied from $1168 by
;       POST_LOAD (Z80_VEC_INSTALL); it is data here, written into at run time.
Z80_VEC_DEST:
        .byte   $FF                                              ; $0FFF

; ---------------------------------------------------------------------------
; POST_LOAD -- entered (JMP $1000) once the loader has finished relocating itself.
; [AI] Resets text/video/keyboard to the monitor defaults, then checks the boot result the
;       relocator left in A: A==6 means "booted from slot 6 with a SoftCard" -> proceed to the
;       SoftCard install (SOFTCARD_INSTALL); otherwise print "MUST BOOT FROM SLOT SIX" and
;       drop to the monitor. NOTE: $1000-$1002 get self-patched later into the Z-80 jump
;       (C3 00 DA = Z-80 'JP $DA00') -- after that point these bytes are Z-80 code, not 6502.
; ---------------------------------------------------------------------------
POST_LOAD:
        LDA LC_ROM_BANK2_WR          ; $1000  AD 81 C0  (later overwritten with Z-80 JP $DA00)
        LDA LC_ROM_BANK2_WR          ; $1003  AD 81 C0
        JSR SLOT_TO_Y                ; $1006  20 7D 0F
        PHA                          ; $1009  48
        STA LC_RAM_BANK1_RD,X        ; $100A  9D 88 C0  motor off
        LDA #$00                     ; $100D  A9 00
        STA SCRN_HOLE_0478_S0,Y      ; $100F  99 78 04  clear per-drive track cells
        STA SCRN_HOLE_04F8_S0,Y      ; $1012  99 F8 04
        JSR TEXT                     ; $1015  20 2F FB
        JSR SETVID                   ; $1018  20 93 FE
        JSR SETKBD                   ; $101B  20 89 FE
        PLA                          ; $101E  68
        LDX #$FF                     ; $101F  A2 FF
        TXS                          ; $1021  9A      reset the stack
        CMP #$06                     ; $1022  C9 06    slot-6 boot success?
        BEQ SOFTCARD_INSTALL         ; $1024  F0 10
        LDY #$00                     ; $1026  A0 00
ERR_SLOT_LOOP:
        LDA MSG_SLOT6,Y              ; $1028  B9 4A 11
        BEQ ERR_TO_MON               ; $102B  F0 06
        JSR COUT                     ; $102D  20 ED FD  print "MUST BOOT FROM SLOT SIX"
        INY                          ; $1030  C8
        BNE ERR_SLOT_LOOP            ; $1031  D0 F5
ERR_TO_MON:
        JMP MONZ                     ; $1033  4C 65 FF

; ---------------------------------------------------------------------------
; SOFTCARD_INSTALL -- relocate the install image and probe for the Z-80 SoftCard.
; [AI] Copies the 14-byte Z-80 entry-vector template ($1168) into $0FFF, then the whole install
;       image ($1200-$13FF) down to $0200-$03FF. Walks every $Cn00 firmware page ($C7..$C0)
;       computing a 16-bit checksum and matching the SoftCard signature bytes ($1176/$117A) at
;       offsets 5 and 7 to find the card. The found card's slot drives the page setup below.
; ---------------------------------------------------------------------------
SOFTCARD_INSTALL:
        LDY #$0E                     ; $1036  A0 0E
Z80_VEC_INSTALL:
        LDA Z80_VEC_TEMPLATE,Y       ; $1038  B9 68 11
        STA Z80_VEC_DEST,Y           ; $103B  99 FF 0F
        DEY                          ; $103E  88
        BNE Z80_VEC_INSTALL          ; $103F  D0 F7
COPY_IMG_LO:
        LDA $1200,Y                  ; $1041  B9 00 12  copy install-image low half -> $0200
        STA IN,Y                     ; $1044  99 00 02
        DEY                          ; $1047  88
        BNE COPY_IMG_LO              ; $1048  D0 F7
        LDY #$F1                     ; $104A  A0 F1
COPY_IMG_HI:
        LDA $12FF,Y                  ; $104C  B9 FF 12  copy $1300-$13F0 -> $0300-$03F0
        STA $02FF,Y                  ; $104F  99 FF 02
        DEY                          ; $1052  88
        BNE COPY_IMG_HI              ; $1053  D0 F7
        STY $03B8                    ; $1055  8C B8 03  found-flag := 0
        STY $3C                      ; $1058  84 3C    probe pointer lo := 0
        DEY                          ; $105A  88
        STY $3E                      ; $105B  84 3E    found-slot := $FF (none yet)
        LDY #$C7                     ; $105D  A0 C7    start probing at $C700 (slot 7), down
PROBE_SLOT:
        JSR PROBE_WRITE              ; $105F  20 80 11  (self-modifying touch into $Cn00 page)
        NOP                          ; $1062  EA
        LDA $3E                      ; $1063  A5 3E    already found one?
        BEQ PROBE_SET_FOUND          ; $1065  F0 18
        JSR CHECKSUM16               ; $1067  20 17 11  checksum this firmware page
        STA $40                      ; $106A  85 40
        STX $41                      ; $106C  86 41
        JSR CHECKSUM16               ; $106E  20 17 11  checksum it again (stability check)
        CPX #$00                     ; $1071  E0 00
        BEQ PROBE_NEXT               ; $1073  F0 1E
        CMP $40                      ; $1075  C5 40
        BNE PROBE_NEXT               ; $1077  D0 1A
        CPX $41                      ; $1079  E4 41
        BEQ PROBE_MATCH              ; $107B  F0 1A    stable, nonzero -> candidate card
        BNE PROBE_NEXT               ; $107D  D0 14
PROBE_SET_FOUND:
        INC $3E                      ; $107F  E6 3E    mark "found slot" = this slot's page hi
        STY $03C8                    ; $1081  8C C8 03
        LDA #$00                     ; $1084  A9 00
        STA $03C7                    ; $1086  8D C7 03
        STA $03DE                    ; $1089  8D DE 03
        TYA                          ; $108C  98
        CLC                          ; $108D  18
        ADC #$20                     ; $108E  69 20
        STA $03DF                    ; $1090  8D DF 03
PROBE_NEXT:
        LDX #$00                     ; $1093  A2 00
        BEQ PROBE_RECORD             ; $1095  F0 1F
PROBE_MATCH:
        LDX #$04                     ; $1097  A2 04    compare 5 signature byte pairs
PROBE_SIG_LOOP:
        LDY #$05                     ; $1099  A0 05
        LDA ($3C),Y                  ; $109B  B1 3C    firmware byte at offset 5
        CMP SOFTCARD_SIG5,X          ; $109D  DD 76 11
        BNE PROBE_SIG_NEXT           ; $10A0  D0 09
        LDY #$07                     ; $10A2  A0 07
        LDA ($3C),Y                  ; $10A4  B1 3C    firmware byte at offset 7
        CMP SOFTCARD_SIG7,X          ; $10A6  DD 7A 11
        BEQ PROBE_SIG_HIT            ; $10A9  F0 03
PROBE_SIG_NEXT:
        DEX                          ; $10AB  CA
        BNE PROBE_SIG_LOOP           ; $10AC  D0 EB
PROBE_SIG_HIT:
        INX                          ; $10AE  E8
        CPX #$02                     ; $10AF  E0 02
        BNE PROBE_RECORD             ; $10B1  D0 03
        INC $03B8                    ; $10B3  EE B8 03  bump the SoftCard found-flag
PROBE_RECORD:
        LDY $3D                      ; $10B6  A4 3D    current slot page hi
        TXA                          ; $10B8  8A
        STA $02F8,Y                  ; $10B9  99 F8 02  record per-slot probe result
        DEY                          ; $10BC  88
        CPY #$C0                     ; $10BD  C0 C0    done all slots down to $C0?
        BNE PROBE_SLOT               ; $10BF  D0 9E
        ASL $03B8                    ; $10C1  0E B8 03
        LDA $3E                      ; $10C4  A5 3E    found a card at all?
        CMP #$01                     ; $10C6  C9 01
        BEQ START_ZILOG              ; $10C8  F0 1D    exactly one -> start the Z-80
        STY $3D                      ; $10CA  84 3D
        LDA #$85                     ; $10CC  A9 85
        STA $3C                      ; $10CE  85 3C
        STA $C085                    ; $10D0  8D 85 C0  (slot-5 strobe / SoftCard select side effect)
        LDA $3E                      ; $10D3  A5 3E
        BEQ START_ZILOG              ; $10D5  F0 10
        LDY #$00                     ; $10D7  A0 00
ERR_CARD_LOOP:
        LDA MSG_NO_CARD,Y            ; $10D9  B9 2B 11
        BEQ ERR_CARD_MON             ; $10DC  F0 06
        JSR COUT                     ; $10DE  20 ED FD  print "CAN'T FIND Z80 SOFTCARD"
        INY                          ; $10E1  C8
        BNE ERR_CARD_LOOP            ; $10E2  D0 F5
ERR_CARD_MON:
        JMP MONZ                     ; $10E4  4C 65 FF

; ---------------------------------------------------------------------------
; START_ZILOG -- finish the install and hand the machine to the Z-80.
; [AI] Copies the 16-byte $03EF-block from $13EF (the RPC vector cell area at run address),
;       self-patches POST_LOAD's first 3 bytes into a Z-80 JP $DA00, re-runs LOAD_CPM once
;       through that patched read, installs the 6 monitor IRQ/RESET vector bytes from $1124
;       into $FFF9-$FFFF, and finally JMP $03D2 to enter the relocated 6502 RPC service loop
;       (which loops servicing the running Z-80's CP/M I/O requests).
; ---------------------------------------------------------------------------
START_ZILOG:
        LDY #$10                     ; $10E7  A0 10
RPC_CELL_INSTALL:
        LDA RPC_VEC_TEMPLATE,Y       ; $10E9  B9 EF 13
        STA $03EF,Y                  ; $10EC  99 EF 03
        DEY                          ; $10EF  88
        BNE RPC_CELL_INSTALL         ; $10F0  D0 F7
        LDA #$C3                     ; $10F2  A9 C3    Z-80 JP opcode
        STA POST_LOAD                ; $10F4  8D 00 10  POST_LOAD := JP ...
        LDA #$00                     ; $10F7  A9 00
        STA $1001                    ; $10F9  8D 01 10  ... $DA00 (low)
        LDA #$DA                     ; $10FC  A9 DA
        STA $1002                    ; $10FE  8D 02 10  ... $DA00 (high) -> $1000 is now Z-80 code
        JSR LOAD_CPM                 ; $1101  20 AD 0F  read once more through the patched entry
        LDA #$16                     ; $1104  A9 16
        STA $0FCC                    ; $1106  8D CC 0F  re-tune LOAD_CPM's sector count
        LDY #$06                     ; $1109  A0 06
VEC_INSTALL:
        LDA $1124,Y                  ; $110B  B9 24 11  6 bytes -> $FFF9..$FFFF
        STA $FFF9,Y                  ; $110E  99 F9 FF  (monitor IRQ/NMI/RESET vectors)
        DEY                          ; $1111  88
        BNE VEC_INSTALL              ; $1112  D0 F7
        JMP $03D2                    ; $1114  4C D2 03  enter the relocated 6502 RPC service loop

; ---------------------------------------------------------------------------
; CHECKSUM16 -- 16-bit sum of the 256 bytes at ($3C) (a $Cn00 firmware page).
; [AI] Returns A = low byte, X = carry count (high byte), used by the SoftCard slot probe.
; ---------------------------------------------------------------------------
CHECKSUM16:
        LDA #$00                     ; $1117  A9 00
        TAX                          ; $1119  AA
        TAY                          ; $111A  A8
CHECKSUM_LOOP:
        CLC                          ; $111B  18
        ADC ($3C),Y                  ; $111C  71 3C
        BCC CHECKSUM_NEXT            ; $111E  90 01
        INX                          ; $1120  E8
CHECKSUM_NEXT:
        INY                          ; $1121  C8
        BNE CHECKSUM_LOOP            ; $1122  D0 F7
        RTS                          ; $1124  60

; [AI] Three $03C0 pointers (the RPC service-loop run address), referenced by the vector
;       install ($110B copies 6 of these bytes to $FFF9). $03C0 = the relocated RPC loop entry.
        .byte   $C0, $03, $C0, $03, $C0, $03                     ; $1125  -> $03C0 x3

; [AI] MSG_NO_CARD: high-ASCII "CAN'T FIND Z80 SOFTCARD" with CR padding, NUL-terminated.
MSG_NO_CARD:
        .byte   $8D, $8D, $8D, $8D                               ; $112B  CR CR CR CR
        ASCHI   "CAN'T FIND Z80 SOFTCARD"                        ; $112F
        .byte   $8D                                              ; $1146  trailing CR
        .byte   $8D, $8D, $00                                    ; $1147  CR CR NUL
; [AI] MSG_SLOT6: high-ASCII "MUST BOOT FROM SLOT SIX" with CR padding, NUL-terminated.
MSG_SLOT6:
        .byte   $8D, $8D, $8D, $8D                               ; $114A  CR CR CR CR
        ASCHI   "MUST BOOT FROM SLOT SIX"                        ; $114E
        .byte   $8D                                              ; $1165  trailing CR
        .byte   $8D, $8D                                         ; $1166  CR CR (NUL is the $00 at $1147 reuse)

; [AI] Z80_VEC_TEMPLATE / SOFTCARD_PROBE_OVL: the SoftCard slot-probe handshake. A leading
;       $00 (data, the copy-loop's index-0 cell) followed by 13 bytes of Z-80 code. During the
;       slot scan Z80_VEC_INSTALL copies $1169..$1176 to $1000..$100D, over POST_LOAD's startup
;       instructions (the 6502 has already finished with them). From then on those bytes run on
;       the Z-80, never the 6502: the SoftCard maps the Z-80 reset address ($0000) to Apple
;       $1000, so a slot-probe write (PROBE_WRITE) switches to the Z-80 and lands it at $1000,
;       where it clears the $3E "found" flag and bounces back. The 13 Z-80 bytes are assembled
;       from CPM_BootLoader_ProbeOvl.asm and INCBIN'd; the JR's offset byte ($F2) is the
;       following SOFTCARD_SIG5[0] (so SAVEBIN stops at the JR opcode).
Z80_VEC_TEMPLATE:
        .byte   $00                                              ; $1168  copy index-0 cell (data)
;   >>> CPM_BootLoader_ProbeOvl.asm -- verbatim listing of the INCBIN'd source (regen: inject_incbin_listing) >>>
;
; FOUND   EQU $F03E        ; the 6502's $3E "SoftCard found" flag (Z-80 view of $003E)
; PROBED  EQU $F03D        ; the probed slot's $Cn high byte, set by the 6502 ($003D)
;
;     ORG $1000
;
; PROBE_OVL:
;     XOR A                ; A = 0
;     LD (FOUND),A         ; $3E = 0 -> "SoftCard found in the probed slot"
;     LD L,A               ; HL low = 0
;     LD A,(PROBED)        ; A = probed slot $Cn
;     ADD A,$20            ; $Cn -> $En (the slot's Z-80 I/O page)
;     LD H,A               ; HL = $En00
;     LD (HL),A            ; touch $En00 -> Apple $Cn00 -> switch back to the 6502
;     JR PROBE_OVL         ; loop ($18; offset byte $F2 supplied by host SOFTCARD_SIG5[0])
;   <<< end listing <<<
        .incbin "CPM_BootLoader_ProbeOvl.bin"   ; $1169-$1175  (Z-80; JR offset = SOFTCARD_SIG5[0])

; [AI] SOFTCARD_SIG5 / SOFTCARD_SIG7: signature bytes the slot probe matches at firmware
;       offsets 5 and 7 to recognize a Z-80 SoftCard (5-entry compare, indexed by X).
SOFTCARD_SIG5:
        .byte   $F2, $03, $18, $38                               ; $1176
SOFTCARD_SIG7:
        .byte   $48, $3C, $38, $18, $48, $FF                     ; $117A

; ---------------------------------------------------------------------------
; PROBE_WRITE -- touch a slot's $Cn00 firmware page (SoftCard presence probe).
; [AI] Y holds the page hi ($Cn). It records Y as the current probe slot, self-modifies the
;       $8D $00 $00 STA's high operand byte ($1187) to $Cn so the STA writes into $Cn00, and
;       returns. (The companion read/checksum is done by CHECKSUM16 via the ($3C) pointer.)
; ---------------------------------------------------------------------------
PROBE_WRITE:
        STY $3D                      ; $1180  84 3D    remember current probe slot page hi
        STY PROBE_WRITE+7            ; $1182  8C 87 11  self-modify the STA operand high byte
        STA a:$0000                  ; $1185  8D 00 00  -> writes $Cn00 once relocated
        RTS                          ; $1188  60
        .res    119, $FF    ; $1189  fill

; ===========================================================================
; INSTALL IMAGE ($1200-$13FF) -- DATA from this loader's point of view.
; [AI] SOFTCARD_INSTALL copies $1200-$13FF down to $0200-$03FF. Only AFTER that copy does any
;       of it run, and it runs in two different processors:
;         * $0300-$0349 region: the low part is the GETLN-style input buffer area / scratch and
;           the RPC parameter cells the running system uses.
;         * $034A-$03BF (source $134A-$13BF): Z-80 instructions the SoftCard executes -- small
;           CP/M character-I/O glue (e.g. LD A,($F3BB) / CP 3 / JP NZ,$DB0C; status poll
;           LD A,($E0BE) / AND 2; CALL $DB29 / AND $7F) plus a Z-80 handler-address table
;           ($DD45 $DD3F $DD2B ...) and config bytes. These are NEVER executed by the 6502.
;         * $03C0-$03D9 (source $13C0): the 6502 RPC SERVICE LOOP. At run address $03C0 it does:
;             LDA $C083 / LDA $C083 (LC RAM bank2 read-twice) / STA $C400 / LDA $C081 /
;             JSR $FF3F (RESTORE regs) / JSR $1010 (service one request) / STA $C081 /
;             JSR $FF4A (SAVE regs) / JMP $03C0 (loop). START_ZILOG enters it at $03D2.
;         * $03DA-$03FF (source $13DA): the RPC parameter / vector cells ($03E0 IOB-style block
;           reused by RWTS_ENGINE; the $C0 $03 pointers point back at the $03C0 loop).
; ===========================================================================
        .res    330, $00    ; $1200  zero-filled image low half (-> $0200 GETLN/scratch)
; [AI] $134A-$137B : Z-80 console driver for a slot-3 serial (type-3) card -- these 50
;       bytes are Z-80 code, NOT 6502; assembled by the Z-80 assembler from
;       CPM_BootLoader_ConInit.asm (ORG'd at run address $F34A) and INCBIN'd here.
;       Stored at this offset, copied to Apple $034A at install, executed by the Z-80
;       at $F34A. CPM_BootLoader_ConInit.asm is authoritative.
;   >>> CPM_BootLoader_ConInit.asm -- verbatim listing of the INCBIN'd source (regen: inject_incbin_listing) >>>
;     INCLUDE "apple_softcard.inc"   ; Apple/SoftCard external names (single source of truth)
;
; SLOT3IO EQU $E0BE        ; slot-3 device status register (Apple $C0BE)
;
;     ORG $F34A
;
; CON_STATUS:                     ; $F34A  console status
;     LD A,(SLTTYP3)              ; slot-3 card type
;     CP $03                      ; a type-3 (serial) card?
;     JP NZ,$DB0C                 ; no -> BIOS console status
;     LD A,(SLOT3IO)              ; serial status register
;     RRA                         ; bit0 (char ready) -> carry
;     SBC A,A                     ; A = $FF if ready else $00
;     RET
; CON_INPUT:                      ; $F358  console input
;     CALL $DB29                  ; fetch raw key via BIOS
;     AND $7F                     ; strip high bit
;     RET
; CON_OUTPUT:                     ; $F35E  console output (char in C)
;     LD A,(SLTTYP3)              ; slot-3 card type
;     CP $03                      ; a type-3 (serial) card?
;     JP NZ,$DC3E                 ; no -> BIOS console output
; OUT_WAIT:                       ; $F366
;     LD A,(SLOT3IO)              ; serial status register
;     AND $02                     ; Tx-ready bit set?
;     JR Z,OUT_WAIT               ; spin until ready
;     LD A,C                      ; char to send
;     LD (RPC_ACC),A                ; hand it to the 6502 (A-reg cell)
;     LD HL,$037C                 ; 6502 sub: STA $C0BF ; RTS
;     LD (A_VEC),HL               ; A$VEC := $037C
;     LD HL,(Z_CPU)               ; HL := $En00
;     LD (HL),A                   ; touch $En00 -> RPC runs the 6502
;     RET
;   <<< end listing <<<
        .incbin "CPM_BootLoader_ConInit.bin"   ; $134A-$137B  (Z-80; byte-identical)
; --- $137C..$137F : RPC_SERIAL_OUT -- 6502 routine called by the Z-80 console driver ---
; [AI] The Z-80 ConInit output path sets A$VEC=$037C then switches to the 6502, which runs
;      this (image copy at $137C, run address $037C): push the queued character to the slot-3
;      serial data register and return to the RPC loop. Real 6502 code, not config data.
RPC_SERIAL_OUT:
        STA $C0BF                       ; $137C  (run $037C) char -> slot-3 serial data reg
        RTS                             ; $137F
; [AI] $1380-$13BF : Z-80 console handler-address table + config-block data. 12 little-endian
;      handler addresses ($F34A CON_STATUS, $F358 CON_INPUT, $DB29, $F35E CON_OUTPUT, $DC3E,
;      $DD45 x2, $DD3F x2, $DD2B x2, $DD20) then config bytes. Data.
        .byte   $4A, $F3, $58, $F3, $29, $DB, $5E, $F3, $3E, $DC, $45, $DD, $45, $DD, $3F, $DD ; $1380
        .byte   $3F, $DD, $2B, $DD, $2B, $DD, $20, $1B, $AA, $D9, $D4, $A9, $A8, $1E, $BD, $0B ; $1390
        .byte   $0C, $A0, $00, $0C, $0B, $1D, $0F, $0E, $19, $1E, $1F, $1C, $0B, $5B, $00, $7F ; $13A0
        .byte   $02, $5C, $15, $09, $FF, $FF, $FF, $FF, $02, $05, $03, $04, $00, $00, $02, $00 ; $13B0
; [AI] $13C0 -> runtime $03C0: the 6502 RPC SERVICE LOOP. The heart of the cooperative
;       two-CPU protocol: the Z-80 is master; when it needs the 6502 it switches here (the
;       6502 resumes at $03C9), runs one requested routine, and hands the bus back. The
;       register handoff rides through the monitor RESTORE/SAVE save area ($45-$49). Written
;       as real 6502 below: every operand is absolute, so the bytes are position-independent
;       (identical whether assembled here at $13C0 or run at the copy address $03C0); the JMP
;       target is the literal runtime $03C0. START_ZILOG enters the loop at $03D2 (JMP $03D2).
RPC_SERVICE_LOOP:
        LDA $C083                       ; $13C0  LC: read RAM bank2, write-enable (two reads)
        LDA $C083                       ; $13C3   (the read-twice arms the LC write latch)
        STA $C400                       ; $13C6  slot-4 page access -> switch to the Z-80
        LDA $C081                       ; $13C9  (resume here) LC: read ROM
        JSR RESTORE                     ; $13CC  A,X,Y,P <- $45-$48 (Z-80's call params)
        JSR $1010                       ; $13CF  dispatch the requested 6502 RPC routine
        STA $C081                       ; $13D2  (entry point) LC: read ROM
        JSR SAVE                        ; $13D5  A,X,Y,P,S -> $45-$49 (results for Z-80)
        JMP $03C0                       ; $13D8  loop -> hand the bus back to the Z-80
        .byte   $00, $00                                         ; $13DB  pad cells (-> $03DB, data)
; [AI] $13DA -> runtime $03DA: RPC param block ($03E0 IOB-style cells consumed by RWTS_ENGINE).
